import { useEffect, useState } from "react";
import API from "../api/api";

function LiveScores() {
  const [matches, setMatches] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    fetchLive();

    // 🔥 Auto refresh हर 5 सेकंड
    const interval = setInterval(fetchLive, 5000);
    return () => clearInterval(interval);
  }, []);

  const fetchLive = async () => {
    try {
      setError("");

      const res = await API.get("/cricket/live");

      console.log("🔥 FRONTEND DATA:", res.data);

      const data =
        res.data.matches ||
        res.data.data?.matches ||
        [];

      setMatches(data);
      setLoading(false);

    } catch (err) {
      console.log("❌ ERROR:", err.message);

      setError("Backend not connected");
      setLoading(false);
    }
  };

  return (
    <div className="card">
      <h2>🔥 Live Matches</h2>

      {/* 🔄 Loading */}
      {loading && <p>Loading live matches...</p>}

      {/* ❌ Error */}
      {error && <p style={{ color: "red" }}>{error}</p>}

      {/* 📭 No Data */}
      {!loading && matches.length === 0 && (
        <p>No live matches</p>
      )}

      {/* ✅ Data */}
      {matches.map((m, i) => (
        <div key={i} className="match-card">
          <h3>{m.team1} 🆚 {m.team2}</h3>

          <p><b>Score:</b> {m.score || "N/A"}</p>
          <p><b>Status:</b> {m.status || "N/A"}</p>

          {m.venue && <p><b>Venue:</b> {m.venue}</p>}
          {m.overs && <p><b>Overs:</b> {m.overs}</p>}
        </div>
      ))}
    </div>
  );
}

export default LiveScores;
